def read_int():
    return int(input())


def read_ints():
    return list(map(int, input().split(' ')))


def read_floats():
    return list(map(float, input().split(' ')))


def main():
    r, x, y, x_, y_ = read_ints()
    dist = ((x - x_) ** 2 + (y - y_) ** 2) ** 0.5
    if dist <= r:
        print(0)
    else:
        print(1 if dist > 2 * r else 2)


if __name__ == '__main__':
    main()
